#include <stdio.h>
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        int sum = 0;
        int arr[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
            sum += arr[i];
        }
        if (sum % 2 == 1) {
            printf("YES\n");
        } else {
            int count = 0;
            for (int i = 0; i < n; i++) {
                if (arr[i] % 2 == 1) {
                    count++;
                }
            }
            if (count == 1) {
                printf("YES\n");
            } else {
                printf("NO\n");
            }
        }
    }
    return 0;
}

