const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let t;
let input = [];
readline.on('line', line => {
    if (i == 0) {
        t = parseInt(line);
    } else {
        input.push(line);
    }
    i++;
    if (i == t * 2 + 1) {
        for (let j = 0; j < t; j++) {
            let n = parseInt(input[j * 2]);
            let arr = input[j * 2 + 1].split(' ').map(num => parseInt(num));
            let sum = arr.reduce((a, b) => a + b, 0);
            if (sum % 2 == 1) {
                console.log('YES');
            } else {
                let count = arr.filter(num => num % 2 == 1).length;
                if (count == 1) {
                    console.log('YES');
                } else {
                    console.log('NO');
                }
            }
        }
        readline.close();
    }
});
